namespace ProductReviewsDemo.Infrastructure
{
    public static class ReviewFormatter
    {
        public static IHtmlString ToSafeHtml(string input)
        {
            if (string.IsNullOrWhiteSpace(input))
            {
                return new HtmlString(string.Empty);
            }

            var encoded = HttpUtility.HtmlEncode(input);

            encoded = encoded.Replace("&lt;b&gt;", "<strong>")
                             .Replace("&lt;/b&gt;", "</strong>")
                             .Replace("&lt;strong&gt;", "<strong>")
                             .Replace("&lt;/strong&gt;", "</strong>")
                             .Replace("&lt;i&gt;", "<em>")
                             .Replace("&lt;/i&gt;", "</em>")
                             .Replace("&lt;em&gt;", "<em>")
                             .Replace("&lt;/em&gt;", "</em>");

            encoded = encoded.Replace(Environment.NewLine, "<br />")
                             .Replace("\n", "<br />")
                             .Replace("\r", "<br />");

            return new HtmlString(encoded);
        }
    }
}

namespace ProductReviewsDemo.Controllers
{
    using ProductReviewsDemo.Infrastructure;
    using ProductReviewsDemo.Models;

    public class ProductsController : Controller
    {
        private readonly AppDbContext _db = new AppDbContext();

        public async Task<ActionResult> Details(int id)
        {
            var product = await _db.Products
                .Include(p => p.Reviews)
                .FirstOrDefaultAsync(p => p.Id == id);

            if (product == null)
            {
                return HttpNotFound();
            }

            var model = new ProductPageViewModel
            {
                ProductId = product.Id,
                ProductName = product.Name,
                Reviews = product.Reviews
                    .OrderByDescending(r => r.CreatedUtc)
                    .Select(r => new ReviewViewModel
                    {
                        AuthorName = r.AuthorName,
                        FormattedContent = ReviewFormatter.ToSafeHtml(r.Content).ToHtmlString(),
                        CreatedUtc = r.CreatedUtc
                    })
                    .ToList()
            };

            return View(model);
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
                _db.Dispose();
            }

            base.Dispose(disposing);
        }
    }
}

/* Views/Products/Details.cshtml */
@model ProductReviewsDemo.Models.ProductPageViewModel

@{
    ViewBag.Title = Model.ProductName;
}

<h1>@Model.ProductName</h1>

<section class="reviews">
    <h2>Customer Reviews</h2>

    @if (Model.Reviews == null || !Model.Reviews.Any())
    {
        <p>No reviews yet.</p>
    }
    else
    {
        foreach (var review in Model.Reviews)
        {
            <article class="review">
                <header>
                    <strong>@Html.Encode(review.AuthorName)</strong>
                    <span>@review.CreatedUtc.ToLocalTime().ToString("g")</span>
                </header>
                <div class="review-content">
                    @Html.Raw(review.FormattedContent)
                </div>
            </article>
        }
    }
</section>